public void addValue(Object v) {
    if (v == null) {
        throw new IllegalArgumentException("Null value cannot be added");
    }

    Object obj = (v instanceof Integer) ? Long.valueOf(((Integer) v).longValue()) : v;

    if (!(obj instanceof Comparable)) {
        throw new ClassCastException("Value does not implement Comparable");
    }

    for (Object key : freqTable.keySet()) {
        if (!(key instanceof Comparable)) {
            throw new ClassCastException("Existing value does not implement Comparable");
        }
        Comparable compKey = (Comparable) key;
        if (compKey.compareTo(obj) == 0 || obj.getClass() != key.getClass()) {
            continue;
        }
        try {
            compKey.compareTo(obj);
        } catch (ClassCastException ex) {
            throw new IllegalArgumentException("Value not comparable to existing values.");
        }
    }

    Long count = (Long) freqTable.get(obj);
    if (count == null) {
        freqTable.put(obj, Long.valueOf(1));
    } else {
        freqTable.put(obj, Long.valueOf(count.longValue() + 1));
    }
}

